  // constants: (fcmp pred X, C1) {and|or} (fcmp pred X, C2).
  // For predicates that define a range towards -inf (olt, ole, ult, ule):
  //   OR: take max(C1, C2), AND: take min(C1, C2)
  // For predicates that define a range towards +inf (ogt, oge, ugt, uge):
  //   OR: take min(C1, C2), AND: take max(C1, C2)
  const APFloat *C0, *C1;
  Value *Var0 = nullptr, *Var1 = nullptr;

  // Try to match: (fcmp pred Var, C0) {and|or} (fcmp pred Var, C1)
  if (match(LHS1, m_APFloat(C0)) && match(RHS1, m_APFloat(C1)) &&
      LHS0 == RHS0) {
    Var0 = LHS0;
    Var1 = RHS0;
  }
  // Try to match: (fcmp pred C0, Var) {and|or} (fcmp pred C1, Var)
  else if (match(LHS0, m_APFloat(C0)) && match(RHS0, m_APFloat(C1)) &&
           LHS1 == RHS1) {
    Var0 = LHS1;
    Var1 = RHS1;
    // Swap operands: this effectively changes the predicate
    std::swap(PredL, PredR);
    PredL = FCmpInst::getSwappedPredicate(PredL);
    PredR = FCmpInst::getSwappedPredicate(PredR);
  }
  // Try to match mixed cases: (fcmp pred Var, C0) {and|or} (fcmp pred C1, Var)
  else if (match(LHS1, m_APFloat(C0)) && match(RHS0, m_APFloat(C1)) &&
           LHS0 == RHS1) {
    Var0 = LHS0;
    Var1 = RHS1;
    // Swap RHS to normalize
    PredR = FCmpInst::getSwappedPredicate(PredR);
  }
  // Try to match mixed cases: (fcmp pred C0, Var) {and|or} (fcmp pred Var, C1)
  else if (match(LHS0, m_APFloat(C0)) && match(RHS1, m_APFloat(C1)) &&
           LHS1 == RHS0) {
    Var0 = LHS1;
    Var1 = RHS0;
    // Swap LHS to normalize
    PredL = FCmpInst::getSwappedPredicate(PredL);
  }

  if (Var0 && Var1 && C0 && C1 && PredL == PredR &&
      C0->getSemantics() == C1->getSemantics()) {
    // Predicates that define "less than" ranges
    bool IsLessThanPred = (PredL == FCmpInst::FCMP_OLT ||
                           PredL == FCmpInst::FCMP_OLE ||
                           PredL == FCmpInst::FCMP_ULT ||
                           PredL == FCmpInst::FCMP_ULE);
    // Predicates that define "greater than" ranges
    bool IsGreaterThanPred = (PredL == FCmpInst::FCMP_OGT ||
                              PredL == FCmpInst::FCMP_OGE ||
                              PredL == FCmpInst::FCMP_UGT ||
                              PredL == FCmpInst::FCMP_UGE);

    if (IsLessThanPred || IsGreaterThanPred) {
      int CmpResult = C0->compare(*C1);
      bool C0IsLess = (CmpResult == APFloat::cmpLessThan);

      const APFloat *SelectedC = nullptr;
      FCmpInst *SelectedCmp = nullptr;

      if (IsLessThanPred) {
        // For "less than" predicates:
        // OR: want the larger constant (larger set)
        // AND: want the smaller constant (smaller set)
        if (IsAnd) {
          SelectedC = C0IsLess ? C0 : C1;
        } else {
          SelectedC = C0IsLess ? C1 : C0;
        }
      } else {
        // For "greater than" predicates:
        // OR: want the smaller constant (larger set)
        // AND: want the larger constant (smaller set)
        if (IsAnd) {
          SelectedC = C0IsLess ? C1 : C0;
        } else {
          SelectedC = C0IsLess ? C0 : C1;
        }
      }

      // Determine which original comparison to use based on the selected constant
      bool UseLHS = (SelectedC == C0);
      SelectedCmp = UseLHS ? LHS : RHS;

      // Re-create the comparison with proper operand order
      // Check original operand positions
      Value *OrigLHS0 = LHS->getOperand(0);
      Value *OrigLHS1 = LHS->getOperand(1);
      Value *OrigRHS0 = RHS->getOperand(0);
      Value *OrigRHS1 = RHS->getOperand(1);

      // Determine the variable and constant positions from the original comparison
      Value *Var = nullptr;
      bool VarIsLHS = false;
      if (match(OrigLHS1, m_APFloat(C0))) {
        Var = OrigLHS0;
        VarIsLHS = true;
      } else if (match(OrigLHS0, m_APFloat(C0))) {
        Var = OrigLHS1;
        VarIsLHS = false;
      }

      // Build the simplified comparison
      if (VarIsLHS) {
        // Var < C form
        SelectedCmp = FCmpInst::Create(PredL, Var, ConstantFP::get(LHS->getContext(), *SelectedC));
      } else {
        // C < Var form (need to use swapped predicate)
        SelectedCmp = FCmpInst::Create(FCmpInst::getSwappedPredicate(PredL), 
                                       ConstantFP::get(LHS->getContext(), *SelectedC), Var);
      }
      SelectedCmp->copyFastMathFlags(LHS);
      return SelectedCmp;
    }
  }

  return nullptr;
CODEEOF"}

